const items = $input.all();
const coins = $("110 Coini Belirle").all();

// ============================================
// 🔧 YARDIMCI FONKSİYONLAR
// ============================================

function calcSMA(data, period) {
    let smaArray = new Array(data.length).fill(null);
    for (let i = period - 1; i < data.length; i++) {
        let sum = 0;
        for (let j = 0; j < period; j++) {
            sum += data[i - j] || 0;
        }
        smaArray[i] = sum / period;
    }
    return smaArray;
}

function calcEMA(data, period) {
    let k = 2 / (period + 1);
    let emaArray = new Array(data.length).fill(null);
    let sum = 0;
    let validCount = 0;

    for (let i = 0; i < period && i < data.length; i++) {
        if (data[i] !== null && data[i] !== undefined) {
            sum += data[i];
            validCount++;
        }
    }

    if (validCount < period) return emaArray;
    emaArray[period - 1] = sum / period;

    for (let i = period; i < data.length; i++) {
        if (data[i] !== null && emaArray[i - 1] !== null) {
            emaArray[i] = (data[i] * k) + (emaArray[i - 1] * (1 - k));
        }
    }
    return emaArray;
}

function calcRSI(data, period) {
    let rsiArray = new Array(data.length).fill(null);
    if (data.length < period + 1) return rsiArray;

    let gains = 0, losses = 0;
    for (let i = 1; i <= period; i++) {
        let diff = data[i] - data[i - 1];
        if (diff > 0) gains += diff;
        else losses += Math.abs(diff);
    }

    let avgGain = gains / period;
    let avgLoss = losses / period;

    if (avgLoss === 0) rsiArray[period] = 100;
    else rsiArray[period] = 100 - (100 / (1 + (avgGain / avgLoss)));

    for (let i = period + 1; i < data.length; i++) {
        let diff = data[i] - data[i - 1];
        let currentGain = diff > 0 ? diff : 0;
        let currentLoss = diff < 0 ? Math.abs(diff) : 0;

        avgGain = ((avgGain * (period - 1)) + currentGain) / period;
        avgLoss = ((avgLoss * (period - 1)) + currentLoss) / period;

        if (avgLoss === 0) rsiArray[i] = 100;
        else rsiArray[i] = 100 - (100 / (1 + (avgGain / avgLoss)));
    }
    return rsiArray;
}

function calcATR(highs, lows, closes, period) {
    let trArray = [0];
    for (let i = 1; i < closes.length; i++) {
        let hl = highs[i] - lows[i];
        let hc = Math.abs(highs[i] - closes[i - 1]);
        let lc = Math.abs(lows[i] - closes[i - 1]);
        trArray.push(Math.max(hl, hc, lc));
    }
    return calcSMA(trArray, period);
}

function calcADX(highs, lows, closes, period) {
    if (closes.length < period * 2) return new Array(closes.length).fill(null);

    let plusDM = [0], minusDM = [0], tr = [0];

    for (let i = 1; i < closes.length; i++) {
        let upMove = highs[i] - highs[i - 1];
        let downMove = lows[i - 1] - lows[i];

        plusDM.push(upMove > downMove && upMove > 0 ? upMove : 0);
        minusDM.push(downMove > upMove && downMove > 0 ? downMove : 0);

        let hl = highs[i] - lows[i];
        let hc = Math.abs(highs[i] - closes[i - 1]);
        let lc = Math.abs(lows[i] - closes[i - 1]);
        tr.push(Math.max(hl, hc, lc));
    }

    let smoothedTR = calcEMA(tr, period);
    let smoothedPlusDM = calcEMA(plusDM, period);
    let smoothedMinusDM = calcEMA(minusDM, period);

    let plusDI = [], minusDI = [], dx = [];

    for (let i = 0; i < closes.length; i++) {
        if (smoothedTR[i] && smoothedTR[i] !== 0) {
            plusDI.push((smoothedPlusDM[i] / smoothedTR[i]) * 100);
            minusDI.push((smoothedMinusDM[i] / smoothedTR[i]) * 100);
            let diSum = plusDI[i] + minusDI[i];
            dx.push(diSum !== 0 ? (Math.abs(plusDI[i] - minusDI[i]) / diSum) * 100 : 0);
        } else {
            plusDI.push(0);
            minusDI.push(0);
            dx.push(0);
        }
    }

    return calcEMA(dx, period);
}

// ============================================
// 🚀 ANA İŞLEM DÖNGÜSÜ
// ============================================

let results = [];
let chunkSize = Math.floor(items.length / coins.length);

for (let c = 0; c < coins.length; c++) {
    try {
        let symbol = coins[c].json.symbol;
        let closes = [], highs = [], lows = [], volumes = [];

        // Veriyi çek ve doğrula
        for (let i = 0; i < chunkSize; i++) {
            let idx = (c * chunkSize) + i;
            if (!items[idx] || !items[idx].json) continue;

            let k = items[idx].json;
            let high = parseFloat(k["2"] !== undefined ? k["2"] : k[2]);
            let low = parseFloat(k["3"] !== undefined ? k["3"] : k[3]);
            let close = parseFloat(k["4"] !== undefined ? k["4"] : k[4]);
            let volume = parseFloat(k["5"] !== undefined ? k["5"] : k[5]);

            if (!isNaN(close) && !isNaN(high) && !isNaN(low)) {
                closes.push(close);
                highs.push(high);
                lows.push(low);
                volumes.push(isNaN(volume) ? 0 : volume);
            }
        }

        // Minimum veri kontrolü (200 EMA için en az 210 mum gerekli)
        if (closes.length < 210) {
            continue;
        }

        let currentPrice = closes[closes.length - 1];
        let currIdx = closes.length - 1;
        let prevIdx = currIdx - 1;

        // ============================================
        // 📊 İNDİKATÖRLERİ HESAPLA
        // ============================================

        // RSI (14)
        let rsiArr = calcRSI(closes, 14);
        let currRsi = rsiArr[currIdx];
        let prevRsi = rsiArr[prevIdx];

        // MACD (12, 26, 9)
        let ema12 = calcEMA(closes, 12);
        let ema26 = calcEMA(closes, 26);
        let macdLine = [];
        for (let i = 0; i < closes.length; i++) {
            if (ema12[i] !== null && ema26[i] !== null) {
                macdLine.push(ema12[i] - ema26[i]);
            } else {
                macdLine.push(null);
            }
        }
        let signalLine = calcEMA(macdLine.filter(x => x !== null), 9);

        // Signal line'ı doğru indekse hizala
        let macdValid = macdLine.filter(x => x !== null);
        let currMacd = macdValid[macdValid.length - 1];
        let prevMacd = macdValid[macdValid.length - 2];
        let currSig = signalLine[signalLine.length - 1];
        let prevSig = signalLine[signalLine.length - 2];

        // EMA 200 (Trend Filtresi)
        let ema200 = calcEMA(closes, 200);
        let currEma200 = ema200[currIdx];
        let isUptrend = currentPrice > currEma200;
        let isDowntrend = currentPrice < currEma200;
        let trendStrength = ((currentPrice - currEma200) / currEma200 * 100).toFixed(2);

        // ADX (14) - Trend Gücü - ESNEK EŞİKLER
        let adxArr = calcADX(highs, lows, closes, 14);
        let currADX = adxArr[currIdx] || 0;
        let isTrending = currADX > 18;      // ESKİ: 25, YENİ: 18
        let isStrongTrend = currADX > 30;   // ESKİ: 40, YENİ: 30

        // ATR (14) - Volatilite & SL/TP
        let atrArr = calcATR(highs, lows, closes, 14);
        let currATR = atrArr[currIdx] || 0;

        // Hacim Analizi
        let volMA20 = calcSMA(volumes, 20);
        let currVolume = volumes[currIdx];
        let avgVolume = volMA20[currIdx] || 1;
        let volumeRatio = currVolume / avgVolume;
        let volumeConfirm = volumeRatio > 1.1;  // ESKİ: 1.2, YENİ: 1.1
        let volumeStatus = volumeRatio > 1.5 ? "🔥 Çok Yüksek" : 
                          volumeRatio > 1.1 ? "✅ Yüksek" : 
                          volumeRatio > 0.7 ? "➖ Normal" : "⚠️ Düşük";

        // ============================================
        // 🎯 PRO SİNYAL STRATEJİSİ (GEVŞETİLMİŞ)
        // ============================================

        // MACD Kesişimleri
        let macdBullCross = prevMacd <= prevSig && currMacd > currSig;
        let macdBearCross = prevMacd >= prevSig && currMacd < currSig;

        // RSI Kesişimleri (ESNEK)
        let rsiBullCross = prevRsi <= 35 && currRsi > 35;  // ESKİ: 30, YENİ: 35
        let rsiBearCross = prevRsi >= 65 && currRsi < 65;  // ESKİ: 70, YENİ: 65

        // RSI Bölgeleri
        let rsiOversold = currRsi < 40;
        let rsiOverbought = currRsi > 60;

        let signal = "BEKLE";
        let detail = "";
        let confidence = 0;

        // ============================================
        // 🟢 AL SİNYALİ KOŞULLARI (GEVŞETİLMİŞ)
        // ============================================

        // GÜÇLÜ AL: MACD kesişimi + Uptrend + RSI uygun
        if (macdBullCross && isUptrend && currRsi < 70) {
            signal = "💎 GÜÇLÜ AL";
            detail = "MACD Kesişimi + Uptrend";
            confidence = 80;
            if (isTrending) {
                detail += " + Trend Güçlü";
                confidence += 10;
            }
            if (volumeConfirm) {
                detail += " + Hacim";
                confidence += 5;
            }
        }
        // ORTA AL: RSI dipten çıkış + Uptrend
        else if (rsiBullCross && isUptrend) {
            signal = "🟢 AL";
            detail = "RSI Dipten Çıkış + Uptrend";
            confidence = 70;
            if (isTrending) confidence += 10;
        }
        // ZAYIF AL: MACD kesişimi (trend ne olursa olsun)
        else if (macdBullCross && currRsi < 60) {
            signal = "🟡 ZAYIF AL";
            detail = "MACD Kesişimi (Dikkatli Ol)";
            confidence = 55;
        }
        // EK: RSI aşırı satımda + MACD pozitif
        else if (currRsi < 30 && currMacd > currSig) {
            signal = "🟡 ZAYIF AL";
            detail = "RSI Aşırı Satım + MACD Pozitif";
            confidence = 50;
        }

        // ============================================
        // 🔴 SAT SİNYALİ KOŞULLARI (GEVŞETİLMİŞ)
        // ============================================

        // GÜÇLÜ SAT: MACD kesişimi + Downtrend + RSI uygun
        else if (macdBearCross && isDowntrend && currRsi > 30) {
            signal = "💀 GÜÇLÜ SAT";
            detail = "MACD Kesişimi + Downtrend";
            confidence = 80;
            if (isTrending) {
                detail += " + Trend Güçlü";
                confidence += 10;
            }
            if (volumeConfirm) {
                detail += " + Hacim";
                confidence += 5;
            }
        }
        // ORTA SAT: RSI tepeden dönüş + Downtrend
        else if (rsiBearCross && isDowntrend) {
            signal = "🔴 SAT";
            detail = "RSI Tepeden Dönüş + Downtrend";
            confidence = 70;
            if (isTrending) confidence += 10;
        }
        // ZAYIF SAT: MACD kesişimi (trend ne olursa olsun)
        else if (macdBearCross && currRsi > 40) {
            signal = "🟠 ZAYIF SAT";
            detail = "MACD Kesişimi (Dikkatli Ol)";
            confidence = 55;
        }
        // EK: RSI aşırı alımda + MACD negatif
        else if (currRsi > 70 && currMacd < currSig) {
            signal = "🟠 ZAYIF SAT";
            detail = "RSI Aşırı Alım + MACD Negatif";
            confidence = 50;
        }

        // ============================================
        // ⚠️ FİLTRELER - SADECE ÇOK RİSKLİ DURUMLAR
        // ============================================

        // ADX çok çok düşükse (tam yatay) - iptal
        if (currADX < 12 && signal !== "BEKLE") {
            signal = "BEKLE";
            detail = "Yatay Piyasa (ADX < 12)";
        }

        // ============================================
        // 🛡️ RİSK YÖNETİMİ (ATR BAZLI)
        // ============================================

        let stopLoss, takeProfit1, takeProfit2, riskPercent;

        if (signal.includes("AL")) {
            stopLoss = (currentPrice - (currATR * 1.5)).toFixed(4);
            takeProfit1 = (currentPrice + (currATR * 2.25)).toFixed(4);
            takeProfit2 = (currentPrice + (currATR * 3.75)).toFixed(4);
            riskPercent = ((currATR * 1.5) / currentPrice * 100).toFixed(2);
        } else if (signal.includes("SAT")) {
            stopLoss = (currentPrice + (currATR * 1.5)).toFixed(4);
            takeProfit1 = (currentPrice - (currATR * 2.25)).toFixed(4);
            takeProfit2 = (currentPrice - (currATR * 3.75)).toFixed(4);
            riskPercent = ((currATR * 1.5) / currentPrice * 100).toFixed(2);
        } else {
            stopLoss = "-";
            takeProfit1 = "-";
            takeProfit2 = "-";
            riskPercent = "-";
        }

        // ============================================
        // 📤 SONUÇ
        // ============================================

        results.push({
            json: {
                symbol: symbol,
                currentPrice: currentPrice.toFixed(4),
                signal: signal,
                detail: detail,
                confidence: confidence + "%",

                // İndikatörler
                RSI: currRsi ? currRsi.toFixed(2) : "N/A",
                MACD: currMacd ? currMacd.toFixed(6) : "N/A",
                ADX: currADX ? currADX.toFixed(2) : "N/A",
                ATR: currATR ? currATR.toFixed(4) : "N/A",
                EMA200: currEma200 ? currEma200.toFixed(4) : "N/A",

                // Trend Bilgisi
                trend: isUptrend ? "📈 UPTREND (" + trendStrength + "%)" : "📉 DOWNTREND (" + trendStrength + "%)",
                trendStrength: isTrending ? (isStrongTrend ? "💪 Çok Güçlü" : "✅ Güçlü") : "⚠️ Zayıf",

                // Hacim
                volumeStatus: volumeStatus,
                volumeRatio: volumeRatio.toFixed(2) + "x",

                // Risk Yönetimi
                stopLoss: stopLoss,
                takeProfit1: takeProfit1,
                takeProfit2: takeProfit2,
                riskPercent: riskPercent,

                // Meta
                timestamp: new Date().toLocaleString('tr-TR', { timeZone: 'Europe/Istanbul' }),
                timeframe: "1H"
            }
        });

    } catch (error) {
        // Hata durumunda loglama
        results.push({
            json: {
                symbol: coins[c]?.json?.symbol || "UNKNOWN",
                signal: "⚠️ HATA",
                detail: error.message,
                timestamp: new Date().toLocaleString('tr-TR')
            }
        });
    }
}

return results;
